%% prepare_g41_experiment_sd.m — Stage G4.1 experiment patterns for SD card
%
% Collects the 16 patterns generated by create_g41_experiment_patterns.m,
% stages them in numbered order, and copies to SD card.
%
% Patterns on SD card (pat0001.pat through pat0016.pat):
%   1.  pat01_sq_grating_30deg_gs2        — 30° square, GS2, 16 frames
%   2.  pat02_sq_grating_30deg_gs16       — 30° square, GS16, 16 frames
%   3.  pat03_sq_grating_60deg_gs2        — 60° square, GS2, 32 frames
%   4.  pat04_sq_grating_60deg_gs16       — 60° square, GS16, 32 frames
%   5.  pat05_sine_grating_30deg_gs16     — 30° sine, GS16, 16 frames
%   6.  pat06_sine_grating_60deg_gs16     — 60° sine, GS16, 32 frames
%   7.  pat07_sine_grating_30deg_fine_gs16 — 30° sine fine, GS16, 64 frames
%   8.  pat08_sine_grating_60deg_fine_gs16 — 60° sine fine, GS16, 128 frames
%   9.  pat09_counter_0000_1000_gs2       — Counter, GS2, 1001 frames
%   10. pat10_counter_0000_1000_gs16      — Counter, GS16, 1001 frames
%   11. pat11_luminance_levels_gs2        — Luminance, GS2, 2 frames
%   12. pat12_luminance_levels_gs16       — Luminance, GS16, 16 frames
%   13. pat13_top_on_gs2                  — Top-ON/bottom-OFF, 1 frame
%   14. pat14_left_on_gs2                 — Left-ON/right-OFF, 1 frame
%   15. pat15_web_sq_grating_30deg_gs16   — Web 30° square, GS16 (roundtrip)
%   16. pat16_web_sine_grating_30deg_gs16 — Web 30° sine, GS16 (roundtrip)
%
% Usage:
%   1. Run create_g41_experiment_patterns.m first
%   2. Insert SD card (named PATSD, FAT32)
%      Windows: auto-detects drive letter D:-Z:
%      Mac: auto-detects /Volumes/PATSD, or enter path manually
%   3. Run this script (optionally format for clean dirIndex)
%   4. Eject SD card safely
%
% Uses: detect_sd_card (utils/), prepare_sd_card_crossplatform (tests/fixtures/)

%% Setup
cd(project_root());
clear classes;
addpath(genpath('.'));

pat_dir = fullfile(pwd, 'patterns', 'reference', 'G41_2x12_cw');

%% Collect pattern files in order
pat_listing = dir(fullfile(pat_dir, 'pat*.pat'));
if isempty(pat_listing)
    error('No .pat files found in %s. Run create_g41_experiment_patterns.m first.', pat_dir);
end

% Sort by filename (pat01_, pat02_, etc.)
names = sort({pat_listing.name});
pat_paths = cellfun(@(f) fullfile(pat_dir, f), names, 'UniformOutput', false);

fprintf('=== G4.1 Experiment SD Card Preparation ===\n');
fprintf('Found %d patterns in %s\n\n', length(pat_paths), pat_dir);
for i = 1:length(pat_paths)
    [~, fn, ext] = fileparts(pat_paths{i});
    fprintf('  SD slot %2d: %s%s\n', i, fn, ext);
end

%% Detect SD card (cross-platform)
sd = detect_sd_card('Label', 'PATSD', 'Verbose', true);

if sd.found
    sd_location = sd.path;
    fprintf('\nSD card found: %s (device: %s)\n', sd.path, sd.device);
else
    % Not found — show candidates and prompt
    if ~isempty(sd.candidates)
        fprintf('\nNo SD card named PATSD found. Other volumes detected:\n');
        for c = 1:length(sd.candidates)
            cand = sd.candidates{c};
            fprintf('  %s (label: %s)\n', cand.path, cand.label);
        end
    else
        fprintf('\nNo SD card named PATSD found.\n');
    end

    if ispc
        fprintf('Enter drive letter (e.g. D), or press Enter to stage locally: ');
    else
        fprintf('Enter volume path (e.g. /Volumes/MYSD), or press Enter to stage locally: ');
    end
    reply = input('', 's');

    if isempty(strtrim(reply))
        % Fall back to local staging
        staging_dir = fullfile(pwd, 'tests', 'sd_staging');
        if ~exist(staging_dir, 'dir'), mkdir(staging_dir); end

        fprintf('\nStaging patterns to:\n  %s\n\n', staging_dir);
        for i = 1:length(pat_paths)
            sd_name = sprintf('pat%04d.pat', i);
            copyfile(pat_paths{i}, fullfile(staging_dir, sd_name));
            fprintf('  %s -> %s\n', names{i}, sd_name);
        end
        mapping = struct('success', true, 'staging_dir', staging_dir, ...
                         'num_patterns', length(pat_paths));
        fprintf('\nTo deploy: copy contents of %s to SD card root.\n', staging_dir);
        fprintf('\n=== Done. %d patterns staged locally. ===\n', length(pat_paths));
        return;
    end

    sd_location = strtrim(reply);
end

%% Deploy to SD card using prepare_sd_card_crossplatform
fprintf('\nDeploying %d patterns to %s\n', length(pat_paths), sd_location);
reply = input('Format SD card first? (y/n, recommended for reliable dirIndex): ', 's');
do_format = strcmpi(strtrim(reply), 'y');

mapping = prepare_sd_card_crossplatform(pat_paths, sd_location, ...
    'Format', do_format, 'ValidateDriveName', false);

if ~mapping.success
    fprintf('\n*** SD card deployment FAILED: %s ***\n', mapping.error);
    return;
end

fprintf('\n=== Done. %d patterns staged. ===\n', length(pat_paths));
